+function processPairTrackingModifier(
+    world: World,
+    query: QueryInstance,
+    modifier: Modifier,
+    logic: 'and' | 'or',
+    ctx: World[typeof $internal]
+) {
+    if (!modifier.pairs.length) return;
+    const type = getTrackingType(modifier);
+    if (!type) return;
+
+    query.pairTrackingGroups.push({ logic, type, id: modifier.id, pairs: modifier.pairs });
+    query.isTracking = true;
+
+    for (const pair of modifier.pairs) {
+        const trait = pair[$internal].relation[$internal].trait;
+        if (!hasTraitInstance(ctx.traitInstances, trait)) registerTrait(world, trait);
+        const instance = getTraitInstance(ctx.traitInstances, trait)!;
+        query.traits.push(trait);
+        query.traitInstances.all.push(instance);
+    }
+}
+
+function pairStateKey(entity: Entity, pair: RelationPair, target: Entity) {
+    return `${getEntityId(entity)}:${pair[$internal].relation[$internal].trait.id}:${target}`;
+}
+
+/** Process target-specific relation tracking independently from trait bitmasks. */
+export function processPairTrackingEvent(
+    world: World,
+    entity: Entity,
+    relation: Relation<Trait>,
+    target: Entity,
+    eventType: EventType
+) {
+    const instance = getTraitInstance(world[$internal].traitInstances, relation[$internal].trait);
+    if (!instance) return;
+
+    for (const query of instance.trackingQueries) {
+        if (!query.pairTrackingGroups.length) continue;
+
+        let affected = false;
+        for (const group of query.pairTrackingGroups) {
+            for (const pair of group.pairs) {
+                const pairCtx = pair[$internal];
+                if (pairCtx.relation !== relation || (pairCtx.target !== '*' && pairCtx.target !== target)) continue;
+                affected = true;
+                const key = pairStateKey(entity, pair, target);
+                const previous = query.pairTrackingStates.get(key);
+                // An opposite event in one observation window cancels the pair event.
+                if ((previous === 'add' && eventType === 'remove') || (previous === 'remove' && eventType === 'add')) {
+                    query.pairTrackingStates.delete(key);
+                } else {
+                    query.pairTrackingStates.set(key, eventType);
+                }
+            }
+        }
+        if (!affected) continue;
+
+        const staticMatch = query.relationFilters?.length
+            ? checkQueryWithRelations(world, query, entity)
+            : query.check(world, entity);
+        let pairMatch = true;
+        let hasOr = false;
+        let orMatch = false;
+        for (const group of query.pairTrackingGroups) {
+            let groupMatch = group.logic === 'and';
+            for (const pair of group.pairs) {
+                const expected = group.type;
+                const matches = [...query.pairTrackingStates.entries()].some(([key, state]) =>
+                    state === expected && key.startsWith(`${getEntityId(entity)}:${pair[$internal].relation[$internal].trait.id}:`) &&
+                    (pair[$internal].target === '*' || key.endsWith(`:${pair[$internal].target}`))
+                );
+                if (group.logic === 'and' && !matches) { groupMatch = false; break; }
+                if (group.logic === 'or' && matches) { groupMatch = true; break; }
+            }
+            if (group.logic === 'or') { hasOr = true; orMatch ||= groupMatch; }
+            else if (!groupMatch) pairMatch = false;
+        }
+        if (hasOr && !orMatch) pairMatch = false;
+        if (staticMatch && pairMatch) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
