+import { $internal } from '../common';
+import type { Entity } from '../entity/types';
+import type { Relation, RelationPair } from '../relation/types';
+import { getTraitInstance } from '../trait/trait-instance';
+import type { Trait } from '../trait/types';
+import type { World } from '../world';
+import type { EventType } from './types';
+import { checkQueryWithRelations } from './utils/check-query-with-relations';
+
+const keyFor = (entity: Entity, pair: RelationPair, target: Entity) =>
+    `${entity}:${pair[$internal].relation[$internal].trait.id}:${target}`;
+
+export function processPairTrackingEvent(world: World, entity: Entity, relation: Relation<Trait>, target: Entity, eventType: EventType) {
+    const instance = getTraitInstance(world[$internal].traitInstances, relation[$internal].trait);
+    if (!instance) return;
+    for (const query of instance.trackingQueries) {
+        if (!query.pairTrackingGroups.length) continue;
+        let affected = false;
+        for (const group of query.pairTrackingGroups) for (const pair of group.pairs) {
+            const ctx = pair[$internal];
+            if (ctx.relation !== relation || (ctx.target !== '*' && ctx.target !== target)) continue;
+            affected = true;
+            const key = keyFor(entity, pair, target);
+            const previous = query.pairTrackingStates.get(key);
+            if ((previous === 'add' && eventType === 'remove') || (previous === 'remove' && eventType === 'add')) query.pairTrackingStates.delete(key);
+            else query.pairTrackingStates.set(key, eventType);
+        }
+        if (!affected) continue;
+        const staticMatch = query.relationFilters?.length ? checkQueryWithRelations(world, query, entity) : query.check(world, entity);
+        let matches = true, hasOr = false, orMatches = false;
+        for (const group of query.pairTrackingGroups) {
+            let groupMatches = group.logic === 'and';
+            for (const pair of group.pairs) {
+                const prefix = `${entity}:${pair[$internal].relation[$internal].trait.id}:`;
+                const found = [...query.pairTrackingStates.entries()].some(([key, state]) => state === group.type && key.startsWith(prefix) && (pair[$internal].target === '*' || key.endsWith(`:${pair[$internal].target}`)));
+                if (group.logic === 'and' && !found) { groupMatches = false; break; }
+                if (group.logic === 'or' && found) { groupMatches = true; break; }
+            }
+            if (group.logic === 'or') { hasOr = true; orMatches ||= groupMatches; } else if (!groupMatches) matches = false;
+        }
+        if (hasOr && !orMatches) matches = false;
+        if (staticMatch && matches) query.add(entity); else query.remove(world, entity);
+    }
+}
